export function ProdactCard({ data }: ProductProps) {
    return (
        <div className={styles.card}>
            <div className={styles.cardTitle}>ТОВАРИ</div>
            <Image src={data.image} alt={data.title} width={180} height={140} className={styles.image} />
            <div className={styles.productName}>{data.title}</div>
            <div className={styles.priceRow}>
                <button className={styles.addButton}>+</button>
                <span className={styles.price}>{data.price}$</span>
            </div>
        </div>
    );
}