"use client"

import Image from "next/image"
import { useState } from "react"
import { ProdactCard } from "../components/ProdactCard"
import { mockProducts } from "../services/mockData"
import styles from "./page.module.css"


export default function Home() {
    const [currentProduct, setCurrentProduct] = useState(0)

    const handlePrev = () => {
        setCurrentProduct(prev => prev === 0 ? mockProducts.length - 1 : prev - 1)
    }

    const handleNext = () => {
        setCurrentProduct(prev => prev === mockProducts.length - 1 ? 0 : prev + 1   )
    }
    return (

        <div className={styles.container}>

            <header className={styles.header}>
                <Image src="/images/logo.jpg" alt="Logo" width={180} height={90} className={styles.logo}></Image>
                <h1 className={styles.title}>ТОВАР CREATOR IT ACADEMY</h1>
                <button className={styles.basketButton}><Image src="/images/basket.png" alt="Basket" width={40} height={40} className={styles.basketImage}></Image></button>
            </header>


            <main>

                <button onClick={handlePrev} className={styles.prevButton}>Попередній</button>

                <div className={styles.productsGrid}>
                    {mockProducts.slice(currentProduct, currentProduct + 3).map((product, index) => (
                        <ProdactCard key={product.id} data={product} />
                    ))}
                </div>




                <button onClick={handleNext} className={styles.nextButton}>Наступний</button>

            </main>
            <footer>


            </footer>

        </div>


    )
}